class Solution:
    def bestRotation(self, nums):
        n = len(nums)
        best_k = 0
        best_score = -1
        for k in range(n):
            score = 0
            for i in range(n):
                val = nums[(i + k) % n]
                if val <= i:
                    score += 1
            if score > best_score:
                best_score = score
                best_k = k
        return best_k

