class Solution:
    def bestRotation(self, nums):
        n = len(nums)
        diff = [0] * (n + 1)
        for i in range(n):
            # element i scores at rotation k iff (i - k) mod n >= nums[i];
            # that is a contiguous band of k from a to b (modular)
            a = (i - (n - 1)) % n
            b = (i - nums[i]) % n
            if a <= b:
                diff[a] += 1
                diff[b + 1] -= 1
            else:
                diff[a] += 1
                diff[n] -= 1
                diff[0] += 1
                diff[b + 1] -= 1
        best_k = 0
        best_score = -1
        run = 0
        for k in range(n):
            run += diff[k]
            if run > best_score:
                best_score = run
                best_k = k
        return best_k

