var bestRotation = function(nums) {
    const n = nums.length;
    const diff = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        const a = ((i - (n - 1)) % n + n) % n;
        const b = ((i - nums[i]) % n + n) % n;
        if (a <= b) {
            diff[a] += 1;
            diff[b + 1] -= 1;
        } else {
            diff[a] += 1;
            diff[n] -= 1;
            diff[0] += 1;
            diff[b + 1] -= 1;
        }
    }
    let bestK = 0, bestScore = -1, run = 0;
    for (let k = 0; k < n; k++) {
        run += diff[k];
        if (run > bestScore) {
            bestScore = run;
            bestK = k;
        }
    }
    return bestK;
};
